diff --git a/components/avatar/__tests__/index.test.tsx b/components/avatar/__tests__/index.test.tsx
index d3140f9..a1655b8 100644
--- a/components/avatar/__tests__/index.test.tsx
+++ b/components/avatar/__tests__/index.test.tsx
@@ -28,11 +28,6 @@ describe('Avatar', () => {
     expect(() => avatar.unmount()).not.toThrow()
   })

-  it('should render component of a specified size', () => {
-    const avatar = render(<Avatar size={20} />)
-    expect(avatar).toMatchSnapshot()
-  })
-
   it('group component should render all children', () => {
     const group = mount(
       <Avatar.Group>
@@ -55,7 +50,7 @@ describe('Avatar', () => {

   it('should show count in group', () => {
     const count = 20
-    const group = shallow(<Avatar.Group count={count} />)
+    const group = render(<Avatar.Group count={count} />)
     const text = group.find('.count').text()
     expect(text).toContain(count)
   })

diff --git a/components/shared/__tests__/transition.test.tsx b/components/shared/__tests__/transition.test.tsx
index 0fefc5c..5970478 100644
--- a/components/shared/__tests__/transition.test.tsx
+++ b/components/shared/__tests__/transition.test.tsx
@@ -1,14 +1,14 @@
 import React from 'react'
 import { mount } from 'enzyme'
-import CSSTransition from '../css-transition'
+import CssTransition from '../css-transition'
 import { updateWrapper } from 'tests/utils'

-describe('CSSTransition', () => {
+describe('CssTransition', () => {
   it('should render correctly', () => {
     const wrapper = mount(
-      <CSSTransition visible>
+      <CssTransition visible>
         <span>test</span>
-      </CSSTransition>,
+      </CssTransition>,
     )
     expect(wrapper.text()).toContain('test')
     expect(wrapper.html()).toMatchSnapshot()
@@ -17,9 +17,9 @@ describe('CSSTransition', () => {

   it('should work correctly with time props', async () => {
     const wrapper = mount(
-      <CSSTransition enterTime={300} leaveTime={300}>
+      <CssTransition enterTime={300} leaveTime={300}>
         <span id="test">test</span>
-      </CSSTransition>,
+      </CssTransition>,
     )
     expect(wrapper.find('.transition-enter-active').length).toBe(0)

@@ -34,9 +34,9 @@ describe('CSSTransition', () => {

   it('should clear css-transition classes after hidden', async () => {
     const wrapper = mount(
-      <CSSTransition visible>
+      <CssTransition visible>
         <span>test</span>
-      </CSSTransition>,
+      </CssTransition>,
     )
     // don't remove classes after shown
     await updateWrapper(wrapper, 60)
@@ -57,9 +57,9 @@ describe('CSSTransition', () => {

   it('custom class names should be rendered', async () => {
     const wrapper = mount(
-      <CSSTransition name="test">
+      <CssTransition name="test">
         <span id="test">test</span>
-      </CSSTransition>,
+      </CssTransition>,
     )

     expect(wrapper.find('.test-enter-active').length).toBe(0)

